// Selezione deterministica per data: rotazione pilastri, N brief/giorno × lingue.
// Distribuzione target strategia §4: A 40% B 25% C 15% D 15% E 5%.
const N_PER_DAY = 5;
const LANGS = ['en', 'it'];
const bank = JSON.parse($input.first().json.stdout);
const day = Math.floor(Date.now() / 86400000);
const pool = bank.briefs.filter(b => !b.dynamic);
// ordine pesato per pilastro, offset rotante sul giorno
const order = ['A','A','B','C','A','B','D','A','E','B','C'];
const picks = [];
for (let i = 0; i < N_PER_DAY; i++) {
  const pillar = order[(day + i) % order.length];
  const cands = pool.filter(b => b.pillar === pillar && !picks.find(p => p.id === b.id));
  const chosen = (cands.length ? cands : pool)[(day + i) % (cands.length || pool.length)];
  if (chosen && !picks.find(p => p.id === chosen.id)) picks.push(chosen);
}
const jobs = [];
for (const b of picks) for (const lang of LANGS) {
  if (!b.props[lang]) continue;
  jobs.push({ id: b.id, pillar: b.pillar, template: b.template, lang, props: b.props[lang], hashtagSet: b.hashtagSet, hashtags: bank.hashtagSets[b.hashtagSet] || [] });
}
return jobs.map(j => ({ json: j }));

