// Brand-guard: scarta caption con brand vietati (allineato a CLAUDE.md pre-deploy check).
const BAN = /youtube|google|facebook|instagram|tiktok|amazon|reddit|twitch|outbrain/i;
const out = [];
for (const item of $input.all()) {
  const src = item.json;
  let parsed;
  try { parsed = JSON.parse(src.response || src.data || src.body || '{}'); } catch { parsed = {}; }
  const caption = (parsed.caption || '').trim();
  if (!caption || BAN.test(caption)) {
    // fallback brand-safe: hookLine + CTA, niente brand
    parsed.caption = ((src.props && (src.props.hookLine || src.props.afterCaption)) || 'Zero ads, anywhere.') + ' -> adoff.app';
    parsed.hashtags = src.hashtags || [];
    parsed.aiDisclosure = src.lang === 'it' ? '🤖 Canale brand assistito da AI' : '🤖 AI-assisted brand channel';
    parsed._brandguard = 'fallback';
  }
  const full = `${parsed.caption}\n\n${(parsed.hashtags||[]).join(' ')}\n\n${parsed.aiDisclosure}`;
  out.push({ json: { ...src, caption: parsed.caption, hashtags: parsed.hashtags, aiDisclosure: parsed.aiDisclosure, full_text: full, brandguard: parsed._brandguard || 'ok' } });
}
return out;

// Aggrega il digest giornaliero per Telegram (upload manuale negli scheduler nativi).
const items = $input.all().map(i => i.json);
const lines = items.map(i => `• ${i.id} [${i.lang}] (${i.pillar}) bank/${i.id}__${i.lang}.mp4
  ${i.caption}`);
const text = `🎬 *AdOff Content Factory* — ${items.length} clip pronte (semi-auto)

${lines.join('

')}

➡️ Scarica da video-engine/output/bank/ e carica su TikTok Studio / Meta Business Suite. Poi marca posted.`;
return [{ json: { text } }];
